#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,m,a[N],b[N];
long long k;

inline bool check(int num){
    long long sum=0;
    for(int i=1,j=m;i<=n;i++){
        while(j && a[i]+b[j]>num)
            j--;
        sum+=j;
    }
    return sum>=k;
}

int main(){
    scanf("%d%d%lld",&n,&m,&k);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=m;i++)
        scanf("%d",&b[i]);
    sort(a+1,a+n+1);
    sort(b+1,b+m+1);
    int l=2,r=2e9;
    while(l<r){
        int mid=((long long)l+r)>>1;
        if(check(mid))
            r=mid;
        else
            l=mid+1;
    }
    printf("%d",l);
    return 0;
}
